#include <iostream>

template <typename T>
class Pair {
    T first_;
    T second_;
public:
    Pair(T a, T b) : first_{a}, second_{b} {}
    T first()  const { return first_; }
    T second() const { return second_; }
    T larger() const { return (first_ >= second_) ? first_ : second_; }
};

int main() {
    int a, b;
    std::cin >> a >> b;

    Pair<int> p{a, b};
    std::cout << "First: "  << p.first()  << "\n";
    std::cout << "Second: " << p.second() << "\n";

    if (p.first() == p.second())
        std::cout << "Equal\n";
    else
        std::cout << "Larger: " << p.larger() << "\n";

    return 0;
}

