solution_code:
#include <iostream>

template <typename T>
class Box {
    T value_;
public:
    explicit Box(T v) : value_{v} {}
    T scaled(T factor) const;
};

template <typename T>
T Box<T>::scaled(T factor) const {
    return value_ * factor;
}

int main() {
    int v, s;
    std::cin >> v >> s;
    Box<int> b{v};
    std::cout << "Scaled: " << b.scaled(s) << "\n";
    return 0;
}
